INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3a7ad304-5b1f-42b4-aa43-795bb179eb73',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ruby Bundler — Lock Files, Version Constraints, and Dependency Auditing$escape$,
  $escape$Bundler's Gemfile.lock is your reproducibility guarantee — it pins every gem and its transitive dependencies to exact versions. Never gitignore it in applications (libraries are the exception). The difference between `bundle install` and `bundle update` matters: the former respects the lock file, the latter resolves fresh. Use pessimistic version constraints (`~> 2.1`) in your Gemfile to allow patch updates but block breaking minor changes. For auditing, `bundler-audit` checks your lock file against the Ruby Advisory Database — run `bundle audit check --update` in CI to catch known CVEs before they ship. `bundle outdated` gives a diff of what's stale. If you're on Ruby 3.x, `bundle exec` ensures every command runs against your locked dependency graph, not whatever gems are installed globally. For monorepos or multi-app setups, scope lock files per app and use `BUNDLE_GEMFILE` env var to point Bundler at the right manifest.$escape$,
  $escape$# Gemfile
source 'https://rubygems.org'

gem 'rails', '~> 7.1'
gem 'pg',    '~> 1.5'
gem 'redis', '>= 4.0', '< 6.0'

group :development, :test do
  gem 'bundler-audit', require: false
end

# Terminal — audit in CI
# bundle audit check --update
# bundle outdated --strict$escape$,
  $escape$ruby$escape$,
