INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a29c03b4-c2c8-4955-9800-d3b6035745d1',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ruby's Execution Model — MRI, JIT, and Why Cold Starts Still Sting$escape$,
  $escape$Ruby (MRI) is interpreted: your `.rb` files are parsed into an AST, compiled to YARV bytecode, then executed by the YARV virtual machine — all at runtime, every run. There's no ahead-of-time binary. This means every `ruby script.rb` invocation pays the full parse-and-compile tax upfront, which is why Rails cold starts on Lambda or container-per-request setups can hit 800ms–2s before a single line of your business logic runs.

Ruby 3.1 introduced YJIT (a Rust-rewritten, in-process JIT), enabled via `--yjit` or `RUBY_YJIT_ENABLE=1`. YJIT compiles hot bytecode blocks to native machine code lazily — it doesn't eliminate cold start, but it cuts steady-state throughput latency by 15–30% on real Rails workloads per Shopify benchmarks.

For serverless or CLI tools, cold start is the enemy. Strategies: use `bootsnap` to cache bytecode to disk, freeze string literals with `# frozen_string_literal: true` to reduce object allocation during boot, and measure with `time ruby -e 'require_relative "config/application"'` to isolate framework load time from request time.$escape$,
  $escape$# Measure raw Ruby boot cost vs. your app load
# Run from Rails root

# 1. Bare Ruby startup
time ruby -e 'puts "boot done"'

# 2. With bootsnap cache (add to Gemfile: gem 'bootsnap')
BOOTSNAP_CACHE_DIR=tmp/cache ruby -r bootsnap/setup -e 'puts "boot done"'

# 3. Enable YJIT and confirm it's active
RUBY_YJIT_ENABLE=1 ruby --yjit -e 'puts RubyVM::YJIT.enabled?'

# 4. Check YJIT stats in a running process
if defined?(RubyVM::YJIT)
  pp RubyVM::YJIT.runtime_stats
end$escape$,
  $escape$ruby$escape$,
