INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '73b89d13-bc12-4209-8191-672b2848acb7',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ruby's Standard Library — What You Already Have vs When You Need a Gem$escape$,
  $escape$Ruby ships with a surprisingly capable stdlib that developers routinely overlook. `JSON`, `CSV`, `URI`, `Digest`, `Benchmark`, `Logger`, `Pathname`, `FileUtils`, `Set`, `OpenStruct`, and `Net::HTTP` are all zero-dependency. `require 'json'` gets you `JSON.parse` and `JSON.generate`. `require 'digest'` gives you SHA256 without openssl gems. `require 'benchmark'` lets you time blocks inline.

Where stdlib falls short: `Net::HTTP` is functional but verbose — reach for `faraday` or `httpx` for real HTTP clients. `CSV` handles parsing fine but not large streaming datasets efficiently. `Logger` works for simple logging; use `semantic_logger` or `lograge` in production Rails. There's no built-in async primitive beyond `Thread` — `concurrent-ruby` or `async` gem fills that gap. No JSON schema validation, no JWT, no background jobs.

The practical rule: before `bundle add`, run `ri ClassName` or check `ruby-doc.org`. Gems like `activesupport` re-implement things already in stdlib (`Set`, `Pathname`) and add load overhead. Know what 2.x vs 3.x stdlib added — `Data.define` (3.2) and `Fiber::Scheduler` (3.0) are underused built-ins.$escape$,
  $escape$require 'json'
require 'digest'
require 'benchmark'
require 'set'

# All stdlib — no Gemfile entries needed
payload = JSON.parse('{"user": "alice"}')
hash    = Digest::SHA256.hexdigest(payload['user'])
uniques = Set.new(['a', 'b', 'a'])  # => #<Set: {"a", "b"}>

Benchmark.bm do |x|
  x.report('sha256 x1000:') { 1000.times { Digest::SHA256.hexdigest('hello') } }
end

# This DOES need a gem (Net::HTTP is too verbose for real use)
# gem 'httpx'
# HTTPX.get('https://api.example.com/data')$escape$,
  $escape$ruby$escape$,
