INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '93c31521-7cb5-4183-bac7-104e70735387',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ruby in Production — Taming GC Pauses and Runtime Metrics$escape$,
  $escape$Ruby's GC is generational (minor/major) and can introduce latency spikes silently. `GC.stat` is your first stop — it exposes counters like `heap_live_slots`, `major_gc_count`, and `total_allocated_objects` with zero overhead. Ship these to StatsD or Prometheus on every request or via a background thread.

For wall-clock profiling in production, `stackprof` is the de facto standard. It uses `SIGPROF`-based sampling (default 1000 Hz), so overhead is negligible. Wrap hot code paths with `StackProf.run(mode: :wall, raw: true)` and dump results to a file for flamegraph analysis with `stackprof --flamegraph`.

GC pauses specifically? Enable `GC::Profiler` temporarily — not permanently — to capture per-GC elapsed time. Tune aggressiveness via env vars: `RUBY_GC_HEAP_GROWTH_FACTOR=1.1` shrinks heap growth to reduce major GC frequency. For Rails apps, `derailed_benchmarks` identifies which gems allocate most at boot. Combine `GC.compact` (Ruby 2.7+) in Puma's `before_fork` to reduce per-worker heap fragmentation.$escape$,
  $escape$require 'stackprof'
require 'statsd-instrument'

# Sample GC stats and ship to StatsD
def report_gc_metrics
  stat = GC.stat
  StatsD.gauge('ruby.gc.heap_live_slots', stat[:heap_live_slots])
  StatsD.gauge('ruby.gc.major_gc_count', stat[:major_gc_count])
  StatsD.gauge('ruby.gc.total_allocated_objects', stat[:total_allocated_objects])
end

# Profile a specific block in production (sample 1-in-100 requests)
if rand(100) == 0
  StackProf.run(mode: :wall, raw: true, out: '/tmp/stackprof-#{Process.pid}.dump') do
    yield
  end
end$escape$,
